mapper.select:
SELECT c.*, u.username, u.avatar as user_avatar
FROM comments c
JOIN users u ON c.user_id = u.id
WHERE c.post_id = #{postId}
ORDER BY c.created_at ASC
LIMIT #{page}, #{size}

SELECT c.*, u.username, u.avatar as user_avatar
FROM comments c
JOIN users u ON c.user_id = u.id
WHERE c.parent_id = #{parentId}
ORDER BY c.created_at ASC
LIMIT #{page}, #{size}
